
import {
  Users,
  TrendingUp,
  Shield,
  Activity,
  GraduationCap,
  School,
  Music,
  FileText,
  Clock,
  UserPlus,
  Trophy,
  CheckCircle,
  Database,
  ChevronRight,
  ArrowUpRight,
  LayoutDashboard
} from 'lucide-react'
import Link from 'next/link'
import { getAdminStats, getRecentActivity } from '@/src/lib/supabase/queries/dashboard';

export default async function AdminDashboard() {
  const [stats, activityLogs] = await Promise.all([
    getAdminStats(),
    getRecentActivity()
  ]);

  return (
    <div className="relative min-h-screen">
      {/* Background Pattern - Seigaiha (Subtle) */}
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none" style={{
        backgroundImage: `url("data:image/svg+xml,%3Csvg width='20' height='20' viewBox='0 0 20 20' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M1 1h2v2H1V1zm4 0h2v2H5V1zm4 0h2v2H9V1zm4 0h2v2h-2V1zm4 0h2v2h-2V1zm-9 2h2v2H8V3zm4 0h2v2h-2V3zm4 0h2v2h-2V3zm-9 2h2v2H3V5zm4 0h2v2H7V5zm4 0h2v2h-2V5zm-9 2h2v2H-1V7zm4 0h2v2H3V7zm4 0h2v2H7V7zm-8 2h2v2H-1V9zm4 0h2v2H3V9zm4 0h2v2H7V9zm-8 2h2v2H-1v-2zm4 0h2v2H3v-2zm4 0h2v2H7v-2zm-8 2h2v2H-1v-2zm4 0h2v2H3v-2zm4 0h2v2H7v-2z' fill='%239C92AC' fill-opacity='0.4' fill-rule='evenodd'/%3E%3C/svg%3E")`
      }}></div>

      <div className="relative space-y-8 p-6 lg:p-8">
        {/* Header Section */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 border-b border-gray-100 pb-8">
          <div>
            <h1 className="text-4xl font-bold text-gray-900 mb-2 flex items-center gap-3 tracking-tight">
              <span className="p-2 bg-gray-900 rounded-lg text-white">
                <LayoutDashboard className="w-8 h-8" />
              </span>
              <span>Centro de Comando</span>
            </h1>
            <p className="text-gray-600 flex items-center gap-2 text-lg">
              <span className="font-serif font-semibold text-red-700 bg-red-50 px-2 py-0.5 rounded">管理 (Kanri)</span>
              <span className="w-1.5 h-1.5 rounded-full bg-gray-300"></span>
              <span>Visão estratégica e operacional do Nipo School</span>
            </p>
          </div>
          <div className="flex items-center gap-3">
            <div className="flex flex-col items-end">
              <span className="text-xs font-bold text-gray-400 uppercase tracking-wider">Status do Sistema</span>
              <div className="flex items-center gap-2 text-green-700 font-medium bg-green-50 px-3 py-1 rounded-full border border-green-100">
                <span className="relative flex h-2 w-2">
                  <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
                  <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
                </span>
                Operacional
              </div>
            </div>
          </div>
        </div>

        {/* Main KPI Stats Grid */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">

          {/* Alunos */}
          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 hover:shadow-lg hover:border-gray-300 transition-all duration-300 group relative overflow-hidden">
            <div className="absolute right-0 top-0 h-full w-1 bg-gradient-to-b from-purple-500 to-indigo-600 opacity-0 group-hover:opacity-100 transition-opacity"></div>
            <div className="flex justify-between items-start mb-4">
              <div className="p-3 bg-purple-50 rounded-lg text-purple-600 group-hover:bg-purple-100 transition-colors">
                <GraduationCap className="w-6 h-6" />
              </div>
              <span className="text-xs font-bold text-green-600 bg-green-50 px-2 py-1 rounded-full flex items-center gap-1">
                <TrendingUp className="w-3 h-3" /> +12%
              </span>
            </div>
            <div>
              <p className="text-sm font-medium text-gray-500 uppercase tracking-wide">Total de Alunos</p>
              <h3 className="text-3xl font-bold text-gray-900 mt-1">{stats.totalAlunos}</h3>
            </div>
          </div>

          {/* Professores */}
          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 hover:shadow-lg hover:border-gray-300 transition-all duration-300 group relative overflow-hidden">
            <div className="absolute right-0 top-0 h-full w-1 bg-gradient-to-b from-indigo-500 to-blue-600 opacity-0 group-hover:opacity-100 transition-opacity"></div>
            <div className="flex justify-between items-start mb-4">
              <div className="p-3 bg-indigo-50 rounded-lg text-indigo-600 group-hover:bg-indigo-100 transition-colors">
                <Shield className="w-6 h-6" />
              </div>
              <span className="text-xs font-bold text-blue-600 bg-blue-50 px-2 py-1 rounded-full flex items-center gap-1">
                <Users className="w-3 h-3" /> Equipe
              </span>
            </div>
            <div>
              <p className="text-sm font-medium text-gray-500 uppercase tracking-wide">Professores</p>
              <h3 className="text-3xl font-bold text-gray-900 mt-1">{stats.totalProfessores}</h3>
            </div>
          </div>

          {/* Turmas */}
          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 hover:shadow-lg hover:border-gray-300 transition-all duration-300 group relative overflow-hidden">
            <div className="absolute right-0 top-0 h-full w-1 bg-gradient-to-b from-blue-500 to-cyan-600 opacity-0 group-hover:opacity-100 transition-opacity"></div>
            <div className="flex justify-between items-start mb-4">
              <div className="p-3 bg-blue-50 rounded-lg text-blue-600 group-hover:bg-blue-100 transition-colors">
                <School className="w-6 h-6" />
              </div>
              <span className="text-xs font-bold text-green-600 bg-green-50 px-2 py-1 rounded-full flex items-center gap-1">
                <CheckCircle className="w-3 h-3" /> Ativas
              </span>
            </div>
            <div>
              <p className="text-sm font-medium text-gray-500 uppercase tracking-wide">Turmas Regulares</p>
              <h3 className="text-3xl font-bold text-gray-900 mt-1">{stats.totalTurmas}</h3>
            </div>
          </div>

          {/* Instrumentos */}
          <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-200 hover:shadow-lg hover:border-gray-300 transition-all duration-300 group relative overflow-hidden">
            <div className="absolute right-0 top-0 h-full w-1 bg-gradient-to-b from-red-500 to-orange-600 opacity-0 group-hover:opacity-100 transition-opacity"></div>
            <div className="flex justify-between items-start mb-4">
              <div className="p-3 bg-red-50 rounded-lg text-red-600 group-hover:bg-red-100 transition-colors">
                <Music className="w-6 h-6" />
              </div>
              <span className="text-xs font-bold text-gray-500 bg-gray-100 px-2 py-1 rounded-full flex items-center gap-1">
                Catálogo
              </span>
            </div>
            <div>
              <p className="text-sm font-medium text-gray-500 uppercase tracking-wide">Instrumentos</p>
              <h3 className="text-3xl font-bold text-gray-900 mt-1">{stats.totalInstrumentos}</h3>
            </div>
          </div>

        </div>

        <div className="grid lg:grid-cols-3 gap-8">

          {/* Section: Recent Activity (Real Data) */}
          <div className="lg:col-span-2 space-y-5">
            <h2 className="text-xl font-bold text-gray-900 flex items-center gap-2">
              <Activity className="w-5 h-5 text-red-600" />
              Atividade em Tempo Real
            </h2>

            <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
              {activityLogs.length > 0 ? (
                <div className="divide-y divide-gray-100">
                  {activityLogs.map((log) => (
                    <div key={log.id} className="p-4 hover:bg-gray-50 transition-colors flex items-center gap-4 group">
                      <div className={`p-2.5 rounded-lg shadow-sm ${log.type === 'user' ? 'bg-green-50 text-green-600' :
                          log.type === 'turma' ? 'bg-blue-50 text-blue-600' : 'bg-gray-50 text-gray-600'
                        }`}>
                        {log.type === 'user' ? <UserPlus className="w-5 h-5" /> :
                          log.type === 'turma' ? <School className="w-5 h-5" /> : <Database className="w-5 h-5" />}
                      </div>
                      <div className="flex-1 min-w-0">
                        <p className="text-gray-900 font-medium text-sm truncate group-hover:text-red-700 transition-colors">{log.description}</p>
                        <div className="flex items-center gap-3 mt-1 text-xs text-gray-500">
                          <span className="flex items-center gap-1">
                            <Clock className="w-3 h-3" />
                            {new Date(log.created_at).toLocaleString('pt-BR')}
                          </span>
                        </div>
                      </div>
                      <ChevronRight className="w-4 h-4 text-gray-300 group-hover:text-red-400 transform group-hover:translate-x-1 transition-all" />
                    </div>
                  ))}
                </div>
              ) : (
                <div className="p-8 text-center text-gray-500">
                  <p>Nenhuma atividade recente registrada.</p>
                </div>
              )}
              <div className="p-3 bg-gray-50 text-center border-t border-gray-100">
                <Link href="/admin/database" className="text-xs font-bold uppercase tracking-wider text-gray-500 hover:text-red-600 transition-colors">
                  Ver Logs do Sistema
                </Link>
              </div>
            </div>
          </div>

          {/* Section: Quick Actions & Links */}
          <div className="space-y-5">
            <h2 className="text-xl font-bold text-gray-900 flex items-center gap-2">
              <TrendingUp className="w-5 h-5 text-red-600" />
              Acesso Rápido
            </h2>

            <div className="bg-white rounded-xl border border-gray-200 shadow-sm p-5 space-y-4">
              <Link href="/admin/alunos" className="flex items-center justify-between p-3 rounded-lg bg-gray-50 text-gray-700 hover:bg-red-50 hover:text-red-700 transition-all group border border-transparent hover:border-red-100">
                <div className="flex items-center gap-3">
                  <span className="bg-white p-1.5 rounded-md shadow-sm text-gray-500 group-hover:text-red-600">
                    <UserPlus className="w-4 h-4" />
                  </span>
                  <span className="font-medium">Cadastrar Aluno</span>
                </div>
                <ArrowUpRight className="w-4 h-4 opacity-50 group-hover:opacity-100 transition-opacity" />
              </Link>

              <Link href="/admin/turmas/nova" className="flex items-center justify-between p-3 rounded-lg bg-gray-50 text-gray-700 hover:bg-red-50 hover:text-red-700 transition-all group border border-transparent hover:border-red-100">
                <div className="flex items-center gap-3">
                  <span className="bg-white p-1.5 rounded-md shadow-sm text-gray-500 group-hover:text-red-600">
                    <School className="w-4 h-4" />
                  </span>
                  <span className="font-medium">Nova Turma</span>
                </div>
                <ArrowUpRight className="w-4 h-4 opacity-50 group-hover:opacity-100 transition-opacity" />
              </Link>

              <Link href="/admin/configuracoes" className="flex items-center justify-between p-3 rounded-lg bg-gray-50 text-gray-700 hover:bg-red-50 hover:text-red-700 transition-all group border border-transparent hover:border-red-100">
                <div className="flex items-center gap-3">
                  <span className="bg-white p-1.5 rounded-md shadow-sm text-gray-500 group-hover:text-red-600">
                    <Database className="w-4 h-4" />
                  </span>
                  <span className="font-medium">Configurações</span>
                </div>
                <ArrowUpRight className="w-4 h-4 opacity-50 group-hover:opacity-100 transition-opacity" />
              </Link>
            </div>

            <div className="p-4 bg-gradient-to-br from-red-600 to-purple-800 rounded-xl shadow-lg text-white relative overflow-hidden">
              <div className="relative z-10">
                <h3 className="font-bold text-lg mb-1">Precisa de ajuda?</h3>
                <p className="text-white/80 text-sm mb-3">Consulte o manual administrativo para processos detalhados.</p>
                <Link href="/admin/ajuda" className="inline-block bg-white/20 hover:bg-white/30 backdrop-blur-sm px-4 py-2 rounded-lg text-sm font-medium transition-colors">
                  Acessar Central de Ajuda
                </Link>
              </div>
              <div className="absolute top-0 right-0 -mr-4 -mt-4 text-white/10 transform rotate-12">
                <CheckCircle className="w-32 h-32" />
              </div>
            </div>

          </div>

        </div>
      </div>
    </div>
  )
}
